!function(){function readSchedules(){let items=Array.isArray(window.State&&State.schedules)?State.schedules.filter(Boolean):[];if(!items.length)try{const raw=localStorage.getItem("CBT_CACHE_JADWAL");if(raw){const data=JSON.parse(raw)||{};items=Object.keys(data).map(id=>({id,...data[id]}))}}catch(e){}if(window.State&&State.user&&State.user.kelas){const kelas=String(State.user.kelas).toLowerCase();items=items.filter(item=>{const target=item.target_kelas||item.kelas_target||item.kelas||"";if(!target||"SEMUA"===String(target).toUpperCase()||"ALL"===String(target).toUpperCase())return true;return String(target).split(",").map(x=>x.trim().toLowerCase()).filter(Boolean).some(x=>kelas.includes(x)||x.includes(kelas))})}return items}function emptyMarkup(title,body){return `<div class="mobile-empty cbt-empty-state"><div class="mobile-empty-illustration cbt-empty-illustration"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M7 3.75v3M17 3.75v3M4.75 8.5h14.5M6.5 5.75h11A2.5 2.5 0 0 1 20 8.25v9A2.75 2.75 0 0 1 17.25 20H6.75A2.75 2.75 0 0 1 4 17.25v-9a2.5 2.5 0 0 1 2.5-2.5Z"></path><path d="M9 13h6M9 16h3"></path></svg></div><h4>${title}</h4><p>${body}</p></div>`}function showScheduleEmpty(){const list=document.getElementById("mobile-schedule-list"),count=document.getElementById("schedule-count");if(count)count.textContent="0";if(list)list.innerHTML=emptyMarkup("Belum bisa sinkron","Data jadwal ujian masih kosong atau belum aktif. Silakan tunggu jadwal dibuka oleh proktor/admin.")}function setSyncUnavailable(){const btn=document.getElementById("btnSyncAllSoal"),title=document.querySelector("#sync-state-ready .sync-title"),desc=document.querySelector("#sync-state-ready .sync-desc"),info=document.getElementById("sync-ready-count");if(btn){btn.disabled=true;btn.classList.add("is-disabled");btn.innerHTML='<span class="sync-lock-dot"></span> Belum Bisa Sinkron'}if(title)title.textContent="Belum Bisa Sinkron";if(desc)desc.textContent="Data jadwal masih kosong atau belum aktif. Tunggu proktor/admin membuka jadwal ujian.";if(info)info.textContent="Tidak ada paket ujian yang siap diunduh."}function restoreSyncReady(){const btn=document.getElementById("btnSyncAllSoal"),title=document.querySelector("#sync-state-ready .sync-title"),desc=document.querySelector("#sync-state-ready .sync-desc");if(btn){btn.disabled=false;btn.classList.remove("is-disabled");btn.innerHTML='<i class="fas fa-download"></i> Mulai Sinkronisasi'}if(title)title.textContent="Sinkronisasi Soal";if(desc)desc.textContent="Soal ujian akan diunduh ke perangkat Anda."}function refreshEmptyState(){const items=readSchedules();if(!items.length){showScheduleEmpty();setSyncUnavailable();return true}restoreSyncReady();return false}function patchRender(){const old=window.renderMobileSchedule;if("function"!=typeof old||old._emptyStatePatched)return;const wrapped=function(){const result=old.apply(this,arguments);setTimeout(refreshEmptyState,0);return result};wrapped._emptyStatePatched=true;window.renderMobileSchedule=wrapped}function patchSync(){const old=window.syncAllQuestions;if("function"!=typeof old||old._emptyStatePatched)return;const wrapped=function(){if(refreshEmptyState()){if("function"==typeof window.showCustomAlert)showCustomAlert("Belum Bisa Sinkron","Data jadwal ujian masih kosong atau belum aktif. Silakan tunggu proktor/admin membuka jadwal.","ℹ️");return}return old.apply(this,arguments)};wrapped._emptyStatePatched=true;window.syncAllQuestions=wrapped}function boot(){patchRender();patchSync();refreshEmptyState()}document.addEventListener("DOMContentLoaded",()=>setTimeout(boot,0));window.addEventListener("load",()=>{boot();setTimeout(boot,300);setTimeout(boot,1500)});window.CBTEmptyState={refresh:refreshEmptyState}}();
